void solve(int CASE)
{
	ll n, V; cin >> n >> V;
	var p = Vec2<pll>(V + 1);
	fa(i, 1, n) {
		ll h, s, d; cin >> h >> s >> d;
		if (s <= V)p[s].pb({ h,d });
	}

	// h[i] - (V - S) * d[i]
	ll ans = 0;
	fa(S, 1, V) { // 枚举必须拿满的总重量 S

		var pp = vector<pll>(); // 存处理后的物品 { 重量 s, 价值 v }

		fa(s, 1, S) { // 枚举单个物品重量 s

			var tmp = vector<ll>();
			for (const var& [h, d] : p[s])
				tmp.pb(h - (V - S) * d); // 计算贡献

			// 只处理价值最大的前 S / s 个物品
			// 处理的物品总数压缩到 500 * log2(500) 个 (调和级数)
			// 排序总复杂度为 500 * 1e5 * log2(1e5) = 8.5e8 会超时
			// 改用 nth_element，复杂度少掉一个 log2，为 5e7
			int k = min((ll)S / s, (ll)tmp.size()); // 拿贡献前 S / s 大的物品
			nth_element(tmp.begin(), tmp.begin() + k - 1, tmp.end(), greater<>());
			fa(i, 0, k - 1)pp.pb({ s, tmp[i] });
		}

		// 复杂度 O(500 * log2(500) * 500)
		var dp = vector<ll>(S + 1, -LNF); // 存在负价值，初始化负无穷
		dp[0] = 0;
		for (const var& [s, v] : pp) {
			fb(j, S, s) {
				if (dp[j - s] != -LNF)
					dp[j] = max(dp[j], dp[j - s] + v);
			}
		}

		if (dp[S] != -LNF)
			ans = max(ans, dp[S]);
	}
	cout << ans << endl;
	return;
}
